1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const RUNE_BLOCK_OF_3_PRICE = 60;
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	type Item = { type: string };
15	type QuoteStep = { type: "quote"; items: Item[] };
16	type Scenario = { steps: QuoteStep[] };
17	
18	function sumPerItemBasePremiums(items: Item[]): number {
19	  return items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
20	}
21	
22	function isRuneBlockOfThree(items: Item[]): boolean {
23	  return items.length === 3 && items.every((item) => item.type === "rune");
24	}
25	
26	function calculateBasePremium(items: Item[]): number {
27	  if (isRuneBlockOfThree(items)) {
28	    return RUNE_BLOCK_OF_3_PRICE;
29	  }
30	  return sumPerItemBasePremiums(items);
31	}
32	
33	export function runScenario(scenario: unknown): { results: { premium: number }[] } {
34	  const { steps } = scenario as Scenario;
35	  const items = steps[0].items;
36	  const basePremium = calculateBasePremium(items);
37	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
38	  const premium = basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
39	  return { results: [{ premium }] };
40	}
